import React, { useState } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { Button, addToast } from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { bhService } from '../../../services/bh/bhService';
import type { ContractDto } from '../../../services/bh/models';
import { formatDateLocal, formatVnd } from '../../../utils/format';
import styles from '../../../styles/erpPage.module.css';
const HopDongDetailPage: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const dispatch = useAppDispatch();
  const [item, setItem] = useState<ContractDto | null>(null);
  React.useEffect(() => {
    if (!id) return;
    let c = false;
    const t = setTimeout(() => {
      bhService.getContract(id).then(d => { if (!c) setItem(d); })
        .catch(e => { if (!c) dispatch(addToast({ message: e?.message ?? 'Lỗi', type: 'error' })); });
    }, 0);
    return () => { c = true; clearTimeout(t); };
  }, [id, dispatch]);
  if (!item) return <div className={styles.loading}>Đang tải...</div>;
  return (
    <div className={styles.page}>
      <div className={styles.pageHeader}>
        <h1 className={styles.title}>Hợp đồng {item.code}</h1>
        <Button variant="secondary" onClick={() => navigate('/bh/hd')}>Quay lại</Button>
      </div>
      <div className={styles.formCard}>
        <p><b>Khách hàng:</b> {item.customerName}</p>
        <p><b>Ngày:</b> {formatDateLocal(item.contractDate)}</p>
        <p><b>Giá trị:</b> {formatVnd(item.totalAmount)}</p>
        <p><b>Mô tả:</b> {item.description ?? '—'}</p>
      </div>
    </div>
  );
};
export default HopDongDetailPage;
